def show_banner() -> None:
    from rich.console import Console
    from rich.text import Text
    con = Console()
    banner = Text()
    banner.append("\n")
    banner.append("  ╦ ╦╔═╗╔╗ ╦ ╦╔═╗╔═╗╦╔═╔═╗ ╦ ╦╔═╗╔═╗╔╦╗  \n", style="bold bright_green")
    banner.append("  ║║║║╣ ╠╩╗╠═╣╠═╣║  ╠╩╗║╣  ║║║║╣ ╚═╗ ║   \n", style="bold green")
    banner.append("  ╚╩╝╚═╝╚═╝╩ ╩╩ ╩╚═╝╩ ╩╚═╝ ╚╩╝╚═╝╚═╝ ╩   \n", style="bold dark_green")
    banner.append("         Web Application Security & Hacking   \n", style="bright_green")
    banner.append("        [ 100 Levels · OWASP Top 10 · CTF ]  \n", style="green")
    banner.append("\n")
    con.print(banner)

def simulate_boot() -> None:
    import time

    from rich.console import Console
    con = Console()
    steps = [
        ("Initializing web proxy...",         0.15),
        ("Loading attack payloads...",         0.15),
        ("Calibrating injection vectors...",   0.20),
        ("Mapping OWASP vulnerabilities...",   0.15),
        ("Setting up Burp collaborator...",    0.15),
        ("WebHackQuest ready to launch!",      0.10),
    ]
    for msg, delay in steps:
        con.print(f"  [bright_green]>[/bright_green] {msg}")
        time.sleep(delay)

def run() -> None:
    run_game(
        levels=LEVELS, ranks=RANKS, colors=COLORS, save_file=SAVE_FILE,
        game_name=GAME_NAME, show_banner_fn=show_banner,
        simulate_boot_fn=simulate_boot, engine=ENGINE,
        achievement_thresholds=ACHIEVEMENTS,
    )
